// Attach mailbox context to every event item
const mailbox = $('Split mailboxes (1 at a time)').item.json;
const mailboxEmail = mailbox.mailbox_email.toLowerCase();

const results = [];

for (const item of $input.all()) {
  const ev = item.json;
  // Skip working location events and events without attendees (personal blocks)
  if (ev.eventType === 'workingLocation') continue;
  if (ev.eventType === 'focusTime') continue;
  if (ev.eventType === 'outOfOffice') continue;

  // Skip all-day events that have no time component (date-only start)
  if (!ev.start?.dateTime && !ev.start?.date) continue;

  // Determine status from Google's eventStatus field
  const STATUS_MAP = { confirmed: 'confirmed', tentative: 'tentative', cancelled: 'cancelled' };
  const status = STATUS_MAP[ev.status] ?? 'confirmed';

  // Extract meeting URL: prefer hangoutLink, then conferenceData entryPoints
  let meetingUrl = ev.hangoutLink ?? null;
  if (!meetingUrl && ev.conferenceData?.entryPoints) {
    const videoEntry = ev.conferenceData.entryPoints.find(e => e.entryPointType === 'video');
    meetingUrl = videoEntry?.uri ?? null;
  }

  // Parse start/end — handle all-day (date-only) gracefully
  const startAt   = ev.start?.dateTime ?? ev.start?.date ?? null;
  const endAt     = ev.end?.dateTime   ?? ev.end?.date   ?? null;
  const timezone  = ev.start?.timeZone ?? ev.end?.timeZone ?? 'UTC';

  // Attendees array — exclude the calendar resource itself
  const attendees = (ev.attendees ?? []).map(a => ({
    email:          (a.email ?? '').toLowerCase(),
    name:           a.displayName ?? '',
    response_status: a.responseStatus ?? 'needsAction'
  }));

  const attendeeEmails  = attendees.map(a => a.email).filter(Boolean);
  const attendeeDomains = [...new Set(
    attendeeEmails
      .filter(e => e.includes('@'))
      .map(e => e.split('@')[1])
  )];

  const ownDomain = mailboxEmail.split('@')[1];
  const externalEmails = attendeeEmails.filter(e => !e.endsWith('@' + ownDomain));
  const externalDomains = attendeeDomains.filter(d => d !== ownDomain);
  results.push({
    json: {
      // Identity
      mailbox_id:    mailbox.mailbox_id,
      mailbox_email: mailbox.mailbox_email,
      // Event core
      provider_event_id: ev.id,
      title:             ev.summary     ?? '(No title)',
      description:       ev.description ?? '',
      start_at:          startAt,
      end_at:            endAt,
      timezone,
      meeting_url:       meetingUrl,
      status,
      // Attendees
      attendees,
      attendee_emails:  externalEmails,
      attendee_domains: externalDomains,
      // Pass through for debugging
      raw_event: ev
    }
  });
}

return results;

parameters.query:
SELECT ci.client_id
FROM client_identifiers ci
WHERE (
  {{ $json.attendee_emails.length > 0
    ? "ci.identifier_value = ANY(ARRAY[" + $json.attendee_emails.map(e => "'" + e + "'").join(',') + "]::text[])"
    : "false"
  }}
  OR
  {{ $json.attendee_domains.length > 0
    ? "ci.identifier_value = ANY(ARRAY[" + $json.attendee_domains.map(d => "'" + d + "'").join(',') + "]::text[])"
    : "false"
  }}
)
LIMIT 1;

