const allEvents = $('Normalitza event').all();
const allClients = $input.all();

return allClients.map((clientItem, i) => {
  const ev = allEvents[i].json;
  const clientRow = clientItem.json;
  return {
    json: {
      ...ev,
      client_id: clientRow?.client_id ?? null
    }
  };
});

const allEvents = $('Merge client_id').all();
const allMeetings = $input.all();

const results = [];
for (let i = 0; i < allMeetings.length; i++) {
  const ev = allEvents[i].json;
  const meetingRow = allMeetings[i].json;
  if (!ev.attendees?.length) continue;
  for (const a of ev.attendees) {
    results.push({
      json: {
        meeting_id:      meetingRow.meeting_id,
        email:           a.email,
        name:            a.name,
        response_status: a.response_status
      }
    });
  }
}
return results;
